import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Flashcard, QuizQuestion } from "./types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const generateFlashcardsFromNote = async (content: string): Promise<Flashcard[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Transform this note content into a set of learning flashcards. Format as JSON. Content: ${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            front: { type: Type.STRING },
            back: { type: Type.STRING },
            tags: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["front", "back"]
        }
      }
    }
  });

  const raw = JSON.parse(response.text || "[]");
  return raw.map((item: any, idx: number) => ({
    ...item,
    id: `card-${Date.now()}-${idx}`,
    level: 0,
    nextReview: Date.now(),
    lastInterval: 0
  }));
};

export const generateQuiz = async (content: string): Promise<QuizQuestion[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate 3 high-quality multiple choice questions based on this content. Focus on core concepts. Content: ${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctAnswer: { type: Type.INTEGER, description: "Index of the correct option (0-3)" },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "correctAnswer", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const speakExplanation = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Explain this concept concisely and supportively for an ADHD learner: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binaryString = atob(base64Audio);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }

      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("Speech generation failed", error);
  }
};

import React, { useState } from 'react';
import { Note } from '../types';

interface EditorProps {
  note: Note;
  onSave: (note: Note) => void;
  onGenerateCards: (content: string) => void;
  onGenerateQuiz: (content: string) => void;
  isGenerating: boolean;
}

export const Editor: React.FC<EditorProps> = ({ note, onSave, onGenerateCards, onGenerateQuiz, isGenerating }) => {
  const [content, setContent] = useState(note.content);
  const [title, setTitle] = useState(note.title);

  const handleSave = () => {
    onSave({ ...note, title, content, updatedAt: Date.now() });
