import React, { useState } from 'react';
import { Flashcard } from '../types';

interface FlashcardViewProps {
  cards: Flashcard[];
  onReview: (cardId: string, success: boolean) => void;
  onSpeak: (text: string) => void;
  onClose: () => void;
}

export const FlashcardView: React.FC<FlashcardViewProps> = ({ cards, onReview, onSpeak, onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
        <div className="w-20 h-20 bg-gray-800 rounded-full flex items-center justify-center text-3xl text-gray-500">
          <i className="fas fa-layer-group"></i>
        </div>
        <h3 className="text-xl font-bold">No cards ready for review</h3>
        <p className="text-gray-400">Add notes and generate cards to start training!</p>
        <button onClick={onClose} className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500">Back</button>
      </div>
    );
  }

  const card = cards[currentIndex];

  const handleNext = (success: boolean) => {
    onReview(card.id, success);
    setIsFlipped(false);
    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      onClose();
    }
  };

  return (
    <div className="max-w-2xl mx-auto w-full flex flex-col items-center space-y-8 py-10">
      <div className="w-full flex justify-between items-center text-sm font-medium text-gray-400">
        <span>Session Progress</span>
        <span>{currentIndex + 1} / {cards.length}</span>
      </div>

      <div className="w-full bg-gray-800 h-2 rounded-full overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500" 
          style={{ width: `${((currentIndex + 1) / cards.length) * 100}%` }}
        ></div>
      </div>

      <div 
        onClick={() => setIsFlipped(!isFlipped)}
        className="w-full aspect-[4/3] relative cursor-pointer group perspective-1000"
      >
        <div className={`relative w-full h-full transition-transform duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
          {/* Front */}
          <div className="absolute inset-0 w-full h-full bg-gray-900 border-2 border-gray-800 rounded-3xl flex flex-col items-center justify-center p-8 backface-hidden shadow-2xl">
            <span className="absolute top-4 right-6 text-xs text-gray-500 uppercase tracking-widest">Question</span>
            <p className="text-2xl font-semibold text-center leading-snug">{card.front}</p>
            <div className="mt-8 flex gap-2">
              {card.tags.map(t => (
                <span key={t} className="px-2 py-1 bg-gray-800 rounded text-xs text-gray-400">#{t}</span>
              ))}
            </div>
          </div>

          {/* Back */}
          <div className="absolute inset-0 w-full h-full bg-blue-900/20 border-2 border-blue-500/50 rounded-3xl flex flex-col items-center justify-center p-8 backface-hidden rotate-y-180 shadow-2xl">
            <span className="absolute top-4 right-6 text-xs text-blue-400 uppercase tracking-widest">Answer</span>
            <p className="text-xl text-center leading-relaxed text-blue-100">{card.back}</p>
            <button 
               onClick={(e) => { e.stopPropagation(); onSpeak(card.back); }}
               className="mt-6 w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center hover:bg-blue-500 transition shadow-lg"
            >
              <i className="fas fa-volume-up text-white"></i>
            </button>
          </div>
        </div>
      </div>

      <div className="flex gap-4 w-full">
        {!isFlipped ? (
           <button 
             onClick={() => setIsFlipped(true)}
             className="w-full py-4 bg-gray-800 hover:bg-gray-700 rounded-xl font-bold text-lg transition shadow-lg"
           >
             Reveal Answer
           </button>
        ) : (
          <>
            <button 
              onClick={() => handleNext(false)}
              className="flex-1 py-4 bg-red-900/50 hover:bg-red-900 rounded-xl font-bold border border-red-500/50 transition"
            >
              Still Learning
            </button>
            <button 
              onClick={() => handleNext(true)}
              className="flex-1 py-4 bg-green-900/50 hover:bg-green-900 rounded-xl font-bold border border-green-500/50 transition"
            >
              Mastered
            </button>
          </>
        )}
      </div>

      <p className="text-gray-500 text-sm flex items-center gap-2 italic">
        <i className="fas fa-info-circle"></i> Adaptive learning engine will schedule the next review based on your performance.
      </p>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Note, Flashcard } from '../types';

interface KnowledgeGraphProps {
  notes: Note[];
  cards: Flashcard[];
}

export const KnowledgeGraph: React.FC<KnowledgeGraphProps> = ({ notes, cards }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const width = 800;
    const height = 500;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    // Mock nodes and links based on tags and notes
    const nodes: any[] = notes.map(n => ({ id: n.id, name: n.title, type: 'note', val: 10 }));
    const links: any[] = [];

    // Simple connectivity logic: match tags
    notes.forEach((n, i) => {
      notes.forEach((m, j) => {
        if (i < j) {
          // If they share content keywords or just random for visual demo
          links.push({ source: n.id, target: m.id });
        }
      });
    });

    const simulation = d3.forceSimulation(nodes)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(150))
      .force("charge", d3.forceManyBody().strength(-300))
      .force("center", d3.forceCenter(width / 2, height / 2));

    const link = svg.append("g")
      .attr("stroke", "#374151")
      .attr("stroke-opacity", 0.6)
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke-width", 2);

    const node = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .join("g")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        })
      );

    node.append("circle")
      .attr("r", 20)
      .attr("fill", d => d.type === 'note' ? "#3b82f6" : "#f97316")
      .attr("stroke", "#1f2937")
      .attr("stroke-width", 2);

    node.append("text")
      .text(d => d.name)
      .attr("fill", "#e5e7eb")
      .attr("font-size", "10px")
      .attr("dx", 25)
      .attr("dy", 4);

    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node
        .attr("transform", (d: any) => `translate(${d.x},${d.y})`);
    });

    return () => simulation.stop();
  }, [notes, cards]);

  return (
    <div className="w-full h-full bg-gray-950 rounded-xl overflow-hidden flex flex-col relative">
      <div className="absolute top-4 left-4 z-10">
        <h3 className="text-xl font-bold flex items-center gap-2">
          <i className="fas fa-project-diagram text-blue-400"></i>
          Cognitive Neural Map
        </h3>
        <p className="text-xs text-gray-500">Visualizing the links between your learned concepts.</p>
      </div>
      <svg ref={svgRef} viewBox="0 0 800 500" className="w-full h-full" />
    </div>
  );
};

