const INITIAL_NOTE: Note = {
  id: '1',
  title: '后端学习路线与智能体逻辑',
  content: '# 后端学习笔记\n\n## 核心模块\n- **Spring Cloud**: 微服务模式。\n- **Redis**: 缓存与分布式锁。\n- **JVM**: 性能调优与垃圾回收。\n\n## 智能体 AI\n- 推理循环 (ReAct)。\n- 长期记忆存储。\n- 适应性学习模式。',
  updatedAt: Date.now()
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('sili_notes');
    return saved ? JSON.parse(saved) : [INITIAL_NOTE];
  });
  const [cards, setCards] = useState<Flashcard[]>(() => {
    const saved = localStorage.getItem('sili_cards');
    return saved ? JSON.parse(saved) : [];
  });
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('sili_stats');
    return saved ? JSON.parse(saved) : { xp: 0, level: 1, streak: 1, completedCards: 0, lastActive: new Date().toISOString() };
  });

  const [activeNoteId, setActiveNoteId] = useState<string>(notes[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);

  useEffect(() => {
    localStorage.setItem('sili_notes', JSON.stringify(notes));
    localStorage.setItem('sili_cards', JSON.stringify(cards));
    localStorage.setItem('sili_stats', JSON.stringify(stats));
  }, [notes, cards, stats]);

  const activeNote = notes.find(n => n.id === activeNoteId) || notes[0];

  const handleSaveNote = (updatedNote: Note) => {
    setNotes(prev => prev.map(n => n.id === updatedNote.id ? updatedNote : n));
  };

  const handleGenerateCards = async (content: string) => {
    setIsGenerating(true);
    try {
      const newCards = await generateFlashcardsFromNote(content);
      setCards(prev => [...prev, ...newCards]);
      setStats(prev => ({ ...prev, xp: prev.xp + 50 }));
      alert(`成功！生成了 ${newCards.length} 张抽认卡。`);
    } catch (e) {
      alert("生成卡片失败。请检查 API 密钥或网络连接。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateQuiz = async (content: string) => {
    setIsGenerating(true);
    try {
      const questions = await generateQuiz(content);
      setQuiz(questions);
      setView(AppView.REVIEW);
    } catch (e) {
      alert("生成测试失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleReviewCard = (cardId: string, success: boolean) => {
    setCards(prev => prev.map(c => {
      if (c.id === cardId) {
        const nextLevel = success ? Math.min(5, c.level + 1) : 0;
        const interval = success ? (nextLevel || 1) * 24 * 60 * 60 * 1000 : 0;
        return {
          ...c,
          level: nextLevel,
          nextReview: Date.now() + interval,
          lastInterval: interval
        };
      }
      return c;
    }));

    if (success) {
      setStats(prev => ({ 
        ...prev, 
        xp: prev.xp + 10,
        completedCards: prev.completedCards + 1,
        level: Math.floor((prev.xp + 10) / 500) + 1
      }));
    }
  };

  return (
    <div className="flex h-screen bg-gray-950">
      {/* Sidebar */}
      <nav className="w-16 md:w-64 flex flex-col bg-gray-900 border-r border-gray-800 transition-all duration-300">
        <div className="p-6 mb-8 flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-500/20">
            S
          </div>
          <span className="hidden md:block font-bold text-lg tracking-tight">SILI 系统</span>
        </div>

        <div className="flex-1 px-3 space-y-2">
          {[
            { id: AppView.DASHBOARD, icon: 'fa-home', label: '控制台' },
            { id: AppView.EDITOR, icon: 'fa-pen-nib', label: '知识库' },
            { id: AppView.REVIEW, icon: 'fa-graduation-cap', label: '适应性学习' },
            { id: AppView.GRAPH, icon: 'fa-project-diagram', label: '神经图谱' },
          ].map(item => (
            <button
              key={item.id}
