import React, { useState, useRef } from 'react';
import { Note } from '../types';

interface EditorProps {
  note: Note;
  onSave: (note: Note) => void;
  onGenerateCards: (content: string) => void;
  onGenerateQuiz: (content: string) => void;
  onStartDemo: (content: string) => void;
  onImport: (title: string, content: string) => void;
  isGenerating: boolean;
}

export const Editor: React.FC<EditorProps> = ({ note, onSave, onGenerateCards, onGenerateQuiz, onStartDemo, onImport, isGenerating }) => {
  const [content, setContent] = useState(note.content);
  const [title, setTitle] = useState(note.title);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = () => {
    onSave({ ...note, title, content, updatedAt: Date.now() });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      onImport(file.name.replace(/\.[^/.]+$/, ""), text);
      setContent(text);
      setTitle(file.name.replace(/\.[^/.]+$/, ""));
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex flex-col h-full bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
      <div className="flex items-center justify-between p-4 bg-gray-800/50 border-b border-gray-800">
        <input 
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="bg-transparent text-xl font-bold focus:outline-none w-full mr-4 text-orange-400"
          placeholder="笔记标题..."
        />
        <div className="flex gap-2 shrink-0">
          <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".txt,.md" />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="px-3 py-1 bg-gray-700 hover:bg-gray-600 rounded text-sm font-medium transition"
          >
            <i className="fas fa-file-import mr-2"></i>导入
          </button>
          <button 
            onClick={handleSave}
            className="px-3 py-1 bg-green-600 hover:bg-green-500 rounded text-sm font-medium transition"
          >
            <i className="fas fa-save mr-2"></i>保存
          </button>
          <button 
            disabled={isGenerating}
            onClick={() => onStartDemo(content)}
            className="px-3 py-1 bg-pink-600 hover:bg-pink-500 disabled:opacity-50 rounded text-sm font-medium transition"
          >
            <i className="fas fa-play-circle mr-2"></i>动态演示
          </button>
          <button 
            disabled={isGenerating}
            onClick={() => onGenerateCards(content)}
            className="px-3 py-1 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded text-sm font-medium transition"
          >
            <i className="fas fa-bolt mr-2"></i>AI 卡片
          </button>
        </div>
      </div>
      <textarea
        value={content}
        onChange={(e) => setContent(e.target.value)}
        className="flex-1 p-6 bg-transparent resize-none focus:outline-none mono text-gray-300 leading-relaxed"
        placeholder="输入或导入笔记，点击右上方按钮开始智能学习..."
      />
    </div>
  );
};

import React, { useState } from 'react';
import { DemoStep } from '../types';

interface DynamicDemoViewProps {
  steps: DemoStep[];
  onSpeak: (text: string) => void;
  onClose: () => void;
}

export const DynamicDemoView: React.FC<DynamicDemoViewProps> = ({ steps, onSpeak, onClose }) => {
  const [currentStep, setCurrentStep] = useState(0);

  const step = steps[currentStep];

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      const next = currentStep + 1;
      setCurrentStep(next);
      onSpeak(steps[next].description);
    } else {
      onClose();
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-6 flex flex-col h-full">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-bold text-pink-400">重点概念：动态演示</h2>
          <p className="text-gray-400">正在为您深度剖析每一个细节...</p>
        </div>
        <button onClick={onClose} className="text-gray-500 hover:text-white"><i className="fas fa-times text-2xl"></i></button>
      </div>

      <div className="flex-1 flex flex-col items-center">
        {/* Step Visualization Area */}
        <div className="w-full h-80 bg-gray-900 border border-gray-800 rounded-3xl mb-8 flex items-center justify-center relative overflow-hidden group">
          <div className="absolute inset-0 bg-gradient-to-br from-pink-500/5 to-blue-500/5"></div>

          <div className="z-10 text-center p-8 animate-in fade-in zoom-in duration-500">
             <div className="w-24 h-24 bg-pink-600 rounded-full flex items-center justify-center text-white text-4xl mb-6 mx-auto shadow-2xl shadow-pink-500/20">
               {currentStep + 1}
             </div>
             <h3 className="text-2xl font-bold mb-4">{step.title}</h3>
             <p className="text-lg text-gray-300 max-w-lg mx-auto leading-relaxed">{step.description}</p>
             {step.visualHighlight && (
               <div className="mt-4 text-pink-400 text-sm italic">
                 <i className="fas fa-lightbulb mr-2"></i> {step.visualHighlight}
               </div>
             )}
          </div>
        </div>

        {/* Progress Stepper */}
        <div className="w-full flex justify-between gap-2 mb-10">
          {steps.map((_, idx) => (
            <div 
              key={idx}
              className={`h-2 flex-1 rounded-full transition-all duration-300 ${
                idx <= currentStep ? 'bg-pink-500 shadow-[0_0_10px_rgba(236,72,153,0.5)]' : 'bg-gray-800'
              }`}
            />
          ))}
        </div>

        <div className="flex gap-4 w-full max-w-md">
          <button 
            disabled={currentStep === 0}
            onClick={() => { setCurrentStep(s => s - 1); onSpeak(steps[currentStep-1].description); }}
            className="flex-1 py-4 bg-gray-800 hover:bg-gray-700 disabled:opacity-30 rounded-2xl font-bold transition"
          >
            上一步
          </button>
          <button 
            onClick={handleNext}
            className="flex-2 py-4 px-10 bg-gradient-to-r from-pink-600 to-rose-600 hover:from-pink-500 hover:to-rose-500 rounded-2xl font-bold transition shadow-xl shadow-pink-900/20"
          >
            {currentStep === steps.length - 1 ? '完成演示' : '下一步'}
          </button>
        </div>
      </div>

      <div className="mt-auto flex items-center justify-center gap-3 py-6 bg-pink-500/5 rounded-2xl border border-pink-500/10">
        <div className="w-10 h-10 rounded-full bg-pink-500 flex items-center justify-center text-white">
          <i className="fas fa-robot"></i>
        </div>
        <p className="text-pink-200 font-medium">“我会一直陪着你，直到你完全掌握这个知识点哦~”</p>
      </div>
    </div>
  );
};

