import React, { useState } from 'react';
import { QuizQuestion } from '../types';

interface QuizViewProps {
  questions: QuizQuestion[];
  onComplete: (allCorrect: boolean) => void;
  onClose: () => void;
}

export const QuizView: React.FC<QuizViewProps> = ({ questions, onComplete, onClose }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selected, setSelected] = useState<number | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [score, setScore] = useState(0);

  const q = questions[currentIdx];

  const handleAnswer = (idx: number) => {
    if (selected !== null) return;
    setSelected(idx);
    setShowExplanation(true);
    if (idx === q.correctAnswer) setScore(s => s + 1);
  };

  const handleNext = () => {
    if (currentIdx < questions.length - 1) {
      setCurrentIdx(s => s + 1);
      setSelected(null);
      setShowExplanation(false);
    } else {
      onComplete(score === questions.length - 1 || score === questions.length); // 允许错一个或者全对
    }
  };

  return (
    <div className="max-w-2xl mx-auto py-10 flex flex-col h-full">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-bold">阶段挑战：知识巩固</h2>
        <span className="text-gray-500">{currentIdx + 1} / {questions.length}</span>
      </div>

      <div className="bg-gray-900 border border-gray-800 p-8 rounded-3xl mb-6 shadow-xl">
        <p className="text-xl font-medium leading-relaxed mb-8">{q.question}</p>
        <div className="space-y-4">
          {q.options.map((opt, idx) => (
            <button 
              key={idx}
              onClick={() => handleAnswer(idx)}
              className={`w-full text-left p-4 rounded-xl border transition-all ${
                selected === null ? 'border-gray-800 hover:border-blue-500 hover:bg-blue-500/5' :
                idx === q.correctAnswer ? 'border-green-500 bg-green-500/10 text-green-400' :
                idx === selected ? 'border-red-500 bg-red-500/10 text-red-400' : 'border-gray-800 opacity-50'
              }`}
            >
              <span className="mr-3 font-bold">{String.fromCharCode(65 + idx)}.</span> {opt}
            </button>
          ))}
        </div>
      </div>

      {showExplanation && (
        <div className="bg-blue-500/5 border border-blue-500/20 p-6 rounded-2xl mb-8 animate-in slide-in-from-bottom duration-300">
          <h4 className="font-bold text-blue-400 mb-2">解析：</h4>
          <p className="text-gray-300 leading-relaxed">{q.explanation}</p>
        </div>
      )}

      {selected !== null && (
        <button 
          onClick={handleNext}
          className="w-full py-4 bg-blue-600 hover:bg-blue-500 rounded-2xl font-bold transition shadow-lg"
        >
          {currentIdx === questions.length - 1 ? '提交结果' : '下一题'}
        </button>
      )}
    </div>
  );
};

