import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Flashcard, QuizQuestion, DemoStep, LearningPlan } from "./types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// 情感化语音配置
export const speakSweetly = async (text: string, context: "praise" | "explain" | "encourage" = "explain"): Promise<void> => {
  let prompt = text;
  if (context === "praise") prompt = `用超级甜美、崇拜且开心的语气赞美学习者（中文）：${text}`;
  else if (context === "explain") prompt = `用温柔、耐心、大姐姐般的语气详细讲解这个知识点（中文）：${text}`;
  else prompt = `用充满元气、鼓励的语气给学习者加油（中文）：${text}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binaryString = atob(base64Audio);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }
      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("语音生成失败", error);
  }
};

// PDF AI 识别服务
export const analyzePdf = async (base64Pdf: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              data: base64Pdf,
              mimeType: 'application/pdf'
            }
          },
          {
            text: "请作为一名优秀的学术助教，精准识别并提取这份PDF文件中的所有核心知识内容。请以规范的Markdown格式输出，保持清晰的标题层级、重点加粗，并删减无关的页码或页眉信息。请使用中文。"
          }
        ]
      }
    ]
  });
  return response.text || "";
};

export const generateLearningPlan = async (content: string): Promise<LearningPlan> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `基于以下学习材料，为我制定一个循序渐进的学习规划。请使用中文。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          goal: { type: Type.STRING },
          phases: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                estimatedTime: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });
  return JSON.parse(response.text || "{}");
};

export const generateDynamicDemo = async (concept: string): Promise<DemoStep[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `将以下重难点概念分解为4-6个动态演示步骤。请使用中文，解释要极其通俗易懂且带有鼓励性。内容：${concept}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            visualHighlight: { type: Type.STRING, description: "视觉重点描述" }
          },
          required: ["title", "description"]
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

export const generateFlashcardsFromNote = async (content: string): Promise<Flashcard[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `将内容转换为中文学习卡片。JSON格式。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            front: { type: Type.STRING },
            back: { type: Type.STRING },
            tags: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    }
  });
  const raw = JSON.parse(response.text || "[]");
  return raw.map((item: any, idx: number) => ({
    ...item,
    id: `card-${Date.now()}-${idx}`,
    level: 0,
    nextReview: Date.now(),
    lastInterval: 0
  }));
};

export const generateQuiz = async (content: string): Promise<QuizQuestion[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `基于内容生成3个中文选择题。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING }
          }
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

import React, { useState, useRef, useEffect } from 'react';
import { Note } from '../types';

interface EditorProps {
  note: Note;
  onSave: (note: Note) => void;
  onGenerateCards: (content: string) => void;
  onGenerateQuiz: (content: string) => void;
  onStartDemo: (content: string) => void;
  onImport: (title: string, content: string, isPdf: boolean) => void;
  isGenerating: boolean;
}

export const Editor: React.FC<EditorProps> = ({ note, onSave, onGenerateCards, onGenerateQuiz, onStartDemo, onImport, isGenerating }) => {
  const [content, setContent] = useState(note.content);
  const [title, setTitle] = useState(note.title);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync internal state when active note changes
  useEffect(() => {
    setContent(note.content);
    setTitle(note.title);
  }, [note]);

  const handleSave = () => {
    onSave({ ...note, title, content, updatedAt: Date.now() });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const fileName = file.name.replace(/\.[^/.]+$/, "");
    const isPdf = file.type === "application/pdf";

    if (isPdf) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        onImport(fileName, base64, true);
      };
      reader.readAsDataURL(file);
    } else {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        onImport(fileName, text, false);
      };
      reader.readAsText(file);
    }

    // Clear input so same file can be uploaded again
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="flex flex-col h-full bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
      <div className="flex items-center justify-between p-4 bg-gray-800/50 border-b border-gray-800">
        <input 
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="bg-transparent text-xl font-bold focus:outline-none w-full mr-4 text-orange-400"
          placeholder="笔记标题..."
        />
        <div className="flex gap-2 shrink-0">
          <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".txt,.md,.pdf" />
          <button 
            disabled={isGenerating}
            onClick={() => fileInputRef.current?.click()}
            className="px-3 py-1 bg-gray-700 hover:bg-gray-600 disabled:opacity-50 rounded text-sm font-medium transition flex items-center gap-2"
          >
            <i className="fas fa-file-pdf text-red-400"></i>
            导入 PDF/文本
          </button>
          <button 
            onClick={handleSave}
            className="px-3 py-1 bg-green-600 hover:bg-green-500 rounded text-sm font-medium transition"
          >
            <i className="fas fa-save mr-2"></i>保存
          </button>
          <button 
            disabled={isGenerating}
            onClick={() => onStartDemo(content)}
            className="px-3 py-1 bg-pink-600 hover:bg-pink-500 disabled:opacity-50 rounded text-sm font-medium transition"
          >
            <i className="fas fa-play-circle mr-2"></i>动态演示
          </button>
          <button 
            disabled={isGenerating}
            onClick={() => onGenerateCards(content)}
            className="px-3 py-1 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded text-sm font-medium transition"
          >
            <i className="fas fa-bolt mr-2"></i>AI 卡片
          </button>
        </div>
      </div>
      <textarea
        value={content}
        onChange={(e) => setContent(e.target.value)}
        className="flex-1 p-6 bg-transparent resize-none focus:outline-none mono text-gray-300 leading-relaxed"
        placeholder="输入或导入笔记，点击右上方按钮开始智能学习..."
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, Note, Flashcard, UserStats, QuizQuestion, DemoStep, LearningPlan } from './types';
