const INITIAL_NOTE: Note = {
  id: '1',
  title: '欢迎来到 SILI 智能学习',
  content: '# 开始你的进化\n\n- 点击 **导入** 读取本地 Markdown 或 PDF 文件。\n- 使用 **动态演示** 剖析重难点。\n- AI 抽认卡 帮助你形成长期记忆。\n- 最后通过 **测验** 赢得成就奖赏！',
  updatedAt: Date.now()
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('sili_notes_v2');
    return saved ? JSON.parse(saved) : [INITIAL_NOTE];
  });
  const [cards, setCards] = useState<Flashcard[]>(() => {
    const saved = localStorage.getItem('sili_cards_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('sili_stats_v2');
    return saved ? JSON.parse(saved) : { xp: 0, level: 1, streak: 1, completedCards: 0, lastActive: new Date().toISOString() };
  });

  const [activeNoteId, setActiveNoteId] = useState<string>(notes[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingText, setLoadingText] = useState("正在为您构建智能连接...");
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [demoSteps, setDemoSteps] = useState<DemoStep[]>([]);
  const [learningPlan, setLearningPlan] = useState<LearningPlan | null>(null);

  useEffect(() => {
    localStorage.setItem('sili_notes_v2', JSON.stringify(notes));
    localStorage.setItem('sili_cards_v2', JSON.stringify(cards));
    localStorage.setItem('sili_stats_v2', JSON.stringify(stats));
  }, [notes, cards, stats]);

  const activeNote = notes.find(n => n.id === activeNoteId) || notes[0];

  const handleStartDemo = async (content: string) => {
    setLoadingText("正在剖析知识重难点...");
    setIsGenerating(true);
    try {
      const steps = await generateDynamicDemo(content.substring(0, 1000));
      setDemoSteps(steps);
      setView(AppView.DEMO);
      if (steps.length > 0) speakSweetly(steps[0].description);
    } catch (e) {
      alert("演示生成失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleStartQuiz = async (content: string) => {
    setLoadingText("正在为您准备挑战试题...");
    setIsGenerating(true);
    try {
      const questions = await generateQuiz(content.substring(0, 2000));
      setQuizQuestions(questions);
      setView(AppView.QUIZ);
    } catch (e) {
      alert("测验生成失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCreatePlan = async (content: string) => {
    setLoadingText("正在为您量身定制学习方案...");
    setIsGenerating(true);
    try {
      const plan = await generateLearningPlan(content.substring(0, 2000));
      setLearningPlan(plan);
      speakSweetly("已经为你量身定制好了学习规划，我们一起出发吧！", "encourage");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImport = async (title: string, data: string, isPdf: boolean) => {
    if (isPdf) {
      setLoadingText("SILI 正在深度阅读并解析 PDF 内容...");
      setIsGenerating(true);
      try {
        const extractedText = await analyzePdf(data);
        const newNote = { id: Date.now().toString(), title, content: extractedText, updatedAt: Date.now() };
        setNotes([newNote, ...notes]);
        setActiveNoteId(newNote.id);
        speakSweetly("PDF 内容已经成功提取并转化为笔记了哦，来看看吧！", "encourage");
      } catch (e) {
        alert("PDF 识别失败，请检查文件大小或网络。");
      } finally {
        setIsGenerating(false);
      }
    } else {
      const newNote = { id: Date.now().toString(), title, content: data, updatedAt: Date.now() };
      setNotes([newNote, ...notes]);
      setActiveNoteId(newNote.id);
    }
  };

  const handleReviewCard = (cardId: string, success: boolean) => {
    setCards(prev => prev.map(c => {
      if (c.id === cardId) {
        const nextLevel = success ? Math.min(5, c.level + 1) : 0;
        const interval = success ? (nextLevel || 1) * 24 * 60 * 60 * 1000 : 0;
        return { ...c, level: nextLevel, nextReview: Date.now() + interval };
      }
      return c;
    }));
    if (success) setStats(s => ({ ...s, xp: s.xp + 10 }));
  };

