// 情感化语音配置
export const speakSweetly = async (text: string, context: "praise" | "explain" | "encourage" = "explain"): Promise<void> => {
  let prompt = text;
  if (context === "praise") prompt = `用超级甜美、崇拜且开心的语气赞美学习者（中文）：${text}`;
  else if (context === "explain") prompt = `用温柔、耐心、大姐姐般的语气详细讲解这个知识点（中文）：${text}`;
  else prompt = `用充满元气、鼓励的语气给学习者加油（中文）：${text}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binaryString = atob(base64Audio);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }
      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("语音生成失败", error);
  }
};

export const analyzePdf = async (base64Pdf: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              data: base64Pdf,
              mimeType: 'application/pdf'
            }
          },
          {
            text: "请作为一名优秀的学术助教，精准识别并提取这份PDF文件中的所有核心知识内容。请以规范的Markdown格式输出。请使用中文。"
          }
        ]
      }
    ]
  });
  return response.text || "";
};

export const generateLearningPlan = async (content: string): Promise<LearningPlan> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `基于以下学习材料，为我制定一个循序渐进的学习规划。请使用中文。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          goal: { type: Type.STRING },
          phases: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                estimatedTime: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });
  return JSON.parse(response.text || "{}");
};

export const generateDynamicDemo = async (concept: string): Promise<DemoStep[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `将以下重难点概念分解为4-6个动态演示步骤。要求：讲解话术要基于原文且通顺，比喻不要太多（最多1-2个），侧重逻辑推演。请使用中文。内容：${concept}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            visualHighlight: { type: Type.STRING, description: "视觉重点描述" }
          },
          required: ["title", "description"]
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

export const generateFlashcardsFromNote = async (content: string, noteId: string): Promise<Flashcard[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `将以下内容转换为一组中文学习卡片。必须返回 JSON 数组格式。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            front: { type: Type.STRING },
            back: { type: Type.STRING },
            tags: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["front", "back"]
        }
      }
    }
  });
  const raw = JSON.parse(response.text || "[]");
  return raw.map((item: any, idx: number) => ({
    ...item,
    id: `card-${Date.now()}-${idx}`,
    sourceNoteId: noteId,
    level: 0,
    nextReview: Date.now() - 1000, // 确保新生成的立即可见
    lastInterval: 0
  }));
};

export const generateQuiz = async (content: string): Promise<QuizQuestion[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `基于内容生成3个中文选择题。内容：${content}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING }
          }
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

import React, { useState } from 'react';
import { Flashcard } from '../types';

interface FlashcardViewProps {
  cards: Flashcard[];
  onReview: (cardId: string, success: boolean) => void;
  onSpeak: (text: string) => void;
  onNavigateToSource: (noteId: string) => void;
  onClose: () => void;
}

export const FlashcardView: React.FC<FlashcardViewProps> = ({ cards, onReview, onSpeak, onNavigateToSource, onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
        <div className="w-20 h-20 bg-gray-800 rounded-full flex items-center justify-center text-3xl text-gray-500">
          <i className="fas fa-layer-group"></i>
        </div>
        <h3 className="text-xl font-bold text-gray-300">目前没有待复习的记忆颗粒</h3>
        <p className="text-gray-500">去导入一些资料或在编辑器中生成新卡片吧！</p>
        <button onClick={onClose} className="px-8 py-3 bg-blue-600 rounded-2xl hover:bg-blue-500 transition shadow-lg">返回控制台</button>
      </div>
    );
  }

  const card = cards[currentIndex];

  const handleNext = (success: boolean) => {
    onReview(card.id, success);
    setIsFlipped(false);
    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      onClose();
    }
  };

  return (
    <div className="max-w-3xl mx-auto w-full flex flex-col items-center space-y-6 py-6 h-full overflow-hidden">
      {/* Header Info */}
      <div className="w-full flex justify-between items-center px-4">
        <div className="flex items-center gap-4">
           <button onClick={onClose} className="text-gray-500 hover:text-white transition">
             <i className="fas fa-chevron-left mr-2"></i>返回
           </button>
           <span className="px-3 py-1 bg-gray-800 rounded-full text-xs text-gray-400 font-mono">
             卡片 {currentIndex + 1} / {cards.length}
           </span>
        </div>
        <button 
          onClick={() => onNavigateToSource(card.sourceNoteId)}
          className="text-xs text-blue-400 hover:text-blue-300 transition flex items-center gap-1"
        >
          <i className="fas fa-location-arrow"></i> 定位原文
        </button>
      </div>

      {/* Main Card Container - Vertical Layout */}
      <div className="w-full flex-1 flex flex-col bg-gray-900 border border-gray-800 rounded-[32px] overflow-hidden shadow-2xl">

        {/* Top: Question Area */}
        <div className="flex-[4] flex flex-col items-center justify-center p-8 text-center bg-gray-900/50">
           <span className="text-[10px] uppercase tracking-[0.2em] text-gray-600 mb-6 font-bold">知识提问 (Question)</span>
           <h2 className="text-2xl md:text-3xl font-semibold leading-relaxed text-gray-100 max-w-lg">
             {card.front}
           </h2>
           <div className="mt-6 flex flex-wrap justify-center gap-2">
             {card.tags.map(t => (
               <span key={t} className="px-3 py-1 bg-gray-800/50 rounded-lg text-[10px] text-gray-500 font-medium">#{t}</span>
             ))}
           </div>
        </div>

        {/* Divider / Action */}
        <div className="h-px w-full bg-gradient-to-r from-transparent via-gray-800 to-transparent relative">
           {!isFlipped && (
              <div className="absolute inset-0 flex items-center justify-center -translate-y-1/2">
                <button 
                  onClick={() => setIsFlipped(true)}
                  className="px-6 py-2 bg-blue-600 rounded-full text-sm font-bold shadow-xl shadow-blue-900/40 hover:scale-105 active:scale-95 transition-all"
                >
                  揭晓答案
                </button>
              </div>
           )}
        </div>

        {/* Bottom: Answer Area (Scrollable) */}
        <div className={`flex-[6] flex flex-col p-8 transition-all duration-700 bg-blue-600/[0.03] ${!isFlipped ? 'blur-md grayscale opacity-20 pointer-events-none select-none' : 'blur-0'}`}>
           <div className="flex justify-between items-start mb-4">
              <span className="text-[10px] uppercase tracking-[0.2em] text-blue-500/70 font-bold">深度解析 (Answer)</span>
              {isFlipped && (
                <button 
                  onClick={() => onSpeak(card.back)}
                  className="w-8 h-8 rounded-full bg-blue-600/10 text-blue-400 flex items-center justify-center hover:bg-blue-600 hover:text-white transition"
                >
                  <i className="fas fa-volume-up text-xs"></i>
                </button>
              )}
           </div>

           <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
              <p className="text-lg md:text-xl text-gray-300 leading-relaxed whitespace-pre-wrap">
                {isFlipped ? card.back : "••••••••••••••••••••••••••••••••"}
              </p>
           </div>
        </div>
      </div>

      {/* Footer Controls */}
      <div className="w-full flex gap-4 min-h-[64px]">
        {isFlipped ? (
          <>
            <button 
              onClick={() => handleNext(false)}
              className="flex-1 bg-red-900/20 border border-red-500/30 hover:bg-red-900/40 text-red-400 rounded-2xl font-bold transition-all"
            >
              没记住
            </button>
            <button 
              onClick={() => handleNext(true)}
              className="flex-1 bg-green-900/20 border border-green-500/30 hover:bg-green-900/40 text-green-400 rounded-2xl font-bold transition-all"
            >
              已掌握
            </button>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-gray-600 text-sm italic">
             <i className="fas fa-info-circle mr-2"></i> 请先思考答案，点击上方按钮确认
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, Note, Flashcard, UserStats, QuizQuestion, DemoStep, LearningPlan } from './types';
import { Editor } from './components/Editor';
import { FlashcardView } from './components/FlashcardView';
import { KnowledgeGraph } from './components/KnowledgeGraph';
import { DynamicDemoView } from './components/DynamicDemoView';
import { QuizView } from './components/QuizView';
import { RewardView } from './components/RewardView';
import { 
  generateFlashcardsFromNote, 
  generateQuiz, 
  speakSweetly, 
  generateDynamicDemo,
  generateLearningPlan,
  analyzePdf 
} from './geminiService';

const INITIAL_NOTE: Note = {
  id: '1',
  title: '欢迎来到 SILI 智能学习',
  content: '# 开始你的进化\n\n- 点击 **导入** 读取本地 Markdown 或 PDF 文件。\n- 使用 **动态演示** 剖析重难点。\n- AI 抽认卡 帮助你形成长期记忆。\n- 最后通过 **测验** 赢得成就奖赏！',
  updatedAt: Date.now()
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('sili_notes_v3');
    return saved ? JSON.parse(saved) : [INITIAL_NOTE];
  });
  const [cards, setCards] = useState<Flashcard[]>(() => {
    const saved = localStorage.getItem('sili_cards_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('sili_stats_v3');
    return saved ? JSON.parse(saved) : { xp: 0, level: 1, streak: 1, completedCards: 0, lastActive: new Date().toISOString() };
  });

  const [activeNoteId, setActiveNoteId] = useState<string>(notes[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingText, setLoadingText] = useState("正在为您构建智能连接...");
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [demoSteps, setDemoSteps] = useState<DemoStep[]>([]);
  const [learningPlan, setLearningPlan] = useState<LearningPlan | null>(null);

  useEffect(() => {
    localStorage.setItem('sili_notes_v3', JSON.stringify(notes));
    localStorage.setItem('sili_cards_v3', JSON.stringify(cards));
    localStorage.setItem('sili_stats_v3', JSON.stringify(stats));
  }, [notes, cards, stats]);

  const activeNote = notes.find(n => n.id === activeNoteId) || notes[0];

  const handleStartDemo = async (content: string) => {
    setLoadingText("正在为您推演逻辑步骤...");
    setIsGenerating(true);
    try {
      const steps = await generateDynamicDemo(content.substring(0, 1000));
      setDemoSteps(steps);
      setView(AppView.DEMO);
      if (steps.length > 0) speakSweetly(steps[0].description);
    } catch (e) {
      alert("演示生成失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleStartQuiz = async (content: string) => {
    setLoadingText("正在为您准备挑战试题...");
    setIsGenerating(true);
    try {
      const questions = await generateQuiz(content.substring(0, 2000));
      setQuizQuestions(questions);
      setView(AppView.QUIZ);
    } catch (e) {
      alert("测验生成失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCreatePlan = async (content: string) => {
    setLoadingText("正在为您量身定制学习方案...");
    setIsGenerating(true);
    try {
      const plan = await generateLearningPlan(content.substring(0, 2000));
      setLearningPlan(plan);
      speakSweetly("已经为你量身定制好了学习规划，我们一起出发吧！", "encourage");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImport = async (title: string, data: string, isPdf: boolean) => {
    if (isPdf) {
      setLoadingText("SILI 正在深度阅读并解析 PDF 内容...");
      setIsGenerating(true);
      try {
        const extractedText = await analyzePdf(data);
        const newNote = { id: Date.now().toString(), title, content: extractedText, updatedAt: Date.now() };
        setNotes(prev => [newNote, ...prev]);
        setActiveNoteId(newNote.id);
        speakSweetly("PDF 内容已经成功提取并转化为笔记了哦，来看看吧！", "encourage");
      } catch (e) {
        alert("PDF 识别失败。");
      } finally {
        setIsGenerating(false);
      }
    } else {
      const newNote = { id: Date.now().toString(), title, content: data, updatedAt: Date.now() };
      setNotes(prev => [newNote, ...prev]);
      setActiveNoteId(newNote.id);
    }
  };

  const handleGenerateCards = async (content: string) => {
    setLoadingText("正在提取知识卡片...");
    setIsGenerating(true);
    try {
      const newCards = await generateFlashcardsFromNote(content, activeNoteId);
      setCards(prev => [...prev, ...newCards]);
      speakSweetly(`太棒了！我又为你挖掘了 ${newCards.length} 个记忆颗粒，已经存入记忆库啦！`, "praise");
    } catch (e) {
      alert("卡片生成失败。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleReviewCard = (cardId: string, success: boolean) => {
    setCards(prev => prev.map(c => {
      if (c.id === cardId) {
        const nextLevel = success ? Math.min(5, c.level + 1) : 0;
        const interval = success ? (nextLevel || 1) * 24 * 60 * 60 * 1000 : 0;
        return { ...c, level: nextLevel, nextReview: Date.now() + interval };
      }
      return c;
    }));
    if (success) setStats(s => ({ ...s, xp: s.xp + 10 }));
  };

  const handleNavigateToSource = (noteId: string) => {
    const exists = notes.some(n => n.id === noteId);
    if (exists) {
      setActiveNoteId(noteId);
      setView(AppView.EDITOR);
    } else {
      alert("抱歉，该卡片的源笔记可能已被删除。");
    }
  };

  return (
    <div className="flex h-screen bg-gray-950 text-gray-100 overflow-hidden font-sans">
      {/* Sidebar */}
      <nav className="w-16 md:w-64 flex flex-col bg-gray-900 border-r border-gray-800 z-30 transition-all duration-300">
        <div className="p-6 mb-8 flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-pink-500 to-purple-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-pink-500/20">
            S
          </div>
          <span className="hidden md:block font-bold text-lg tracking-tight">SILI System</span>
        </div>

        <div className="flex-1 px-3 space-y-2">
          {[
            { id: AppView.DASHBOARD, icon: 'fa-home', label: '控制台' },
            { id: AppView.EDITOR, icon: 'fa-pen-nib', label: '知识编织' },
            { id: AppView.REVIEW, icon: 'fa-layer-group', label: '记忆强化' },
            { id: AppView.GRAPH, icon: 'fa-project-diagram', label: '脑图谱' },
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setView(item.id as AppView)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition ${
                view === item.id ? 'bg-pink-600/10 text-pink-400 font-semibold shadow-inner' : 'text-gray-500 hover:bg-gray-800'
              }`}
            >
              <i className={`fas ${item.icon} w-5`}></i>
              <span className="hidden md:block text-sm">{item.label}</span>
            </button>
          ))}
        </div>

        <div className="p-4 mt-auto">
          <div className="hidden md:block bg-gray-800/50 rounded-2xl p-4 border border-gray-700/50">
             <div className="flex justify-between text-[10px] mb-2 font-bold text-gray-500">
               <span className="uppercase">LV.{stats.level}</span>
               <span className="text-pink-400">{stats.xp % 500} / 500 XP</span>
             </div>
             <div className="h-1 w-full bg-gray-800 rounded-full overflow-hidden">
               <div className="h-full bg-pink-500 shadow-[0_0_8px_rgba(236,72,153,0.5)] transition-all duration-500" style={{ width: `${(stats.xp % 500) / 5.0}%` }}></div>
             </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 overflow-hidden flex flex-col relative">
        <header className="h-16 flex items-center justify-between px-8 border-b border-gray-800 bg-gray-950/50 backdrop-blur-md z-20">
          <h2 className="text-sm font-medium text-gray-400 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-pink-500 animate-pulse"></span>
            {view === AppView.DASHBOARD && '控制台：准备好今天的飞跃了吗？'}
            {view === AppView.EDITOR && '编辑器：正在编织知识神经元'}
            {view === AppView.REVIEW && '记忆库：正在强化大脑连接'}
            {view === AppView.DEMO && '重点演示：剖析逻辑本质'}
          </h2>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 text-orange-400 font-black text-sm uppercase">
              <i className="fas fa-fire"></i> {stats.streak} 天连击
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 scroll-smooth">
          {view === AppView.DASHBOARD && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-7xl mx-auto">
              <div className="md:col-span-2 space-y-6">
                <section className="bg-gradient-to-r from-pink-900/40 to-indigo-900/40 border border-pink-500/20 p-8 rounded-[32px] relative overflow-hidden group shadow-2xl">
                  <div className="relative z-10">
                    <h1 className="text-3xl font-bold mb-4">定制智能学习方案</h1>
                    <p className="text-pink-100/60 max-w-md mb-6 leading-relaxed">基于你最新的笔记内容，我将为你生成一个科学的学习周期和重点提示。</p>
                    <button 
                      onClick={() => handleCreatePlan(activeNote.content)}
