import React, { useState, useRef } from 'react';
import { Flashcard } from '../types';
import html2canvas from 'html2canvas';

interface FlashcardViewProps {
  cards: Flashcard[];
  onReview: (cardId: string, success: boolean) => void;
  onSpeak: (text: string) => void;
  onNavigateToSource: (noteId: string) => void;
  onClose: () => void;
}

export const FlashcardView: React.FC<FlashcardViewProps> = ({ cards, onReview, onSpeak, onNavigateToSource, onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  if (cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
        <div className="w-20 h-20 bg-gray-800 rounded-full flex items-center justify-center text-3xl text-gray-500">
          <i className="fas fa-layer-group"></i>
        </div>
        <h3 className="text-xl font-bold text-gray-300">目前没有待复习的记忆颗粒</h3>
        <button onClick={onClose} className="px-8 py-3 bg-blue-600 rounded-2xl hover:bg-blue-500 transition">返回</button>
      </div>
    );
  }

  const card = cards[currentIndex];

  const handleNext = (success: boolean) => {
    onReview(card.id, success);
    setIsFlipped(false);
    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      onClose();
    }
  };

  const handleExportImage = async () => {
    if (!cardRef.current) return;
    const canvas = await html2canvas(cardRef.current, {
      backgroundColor: '#0a0a0a',
      scale: 2
    });
    const link = document.createElement('a');
    link.download = `SILI_Card_${card.id}.png`;
    link.href = canvas.toDataURL();
    link.click();
  };

  return (
    <div className="max-w-3xl mx-auto w-full flex flex-col items-center space-y-6 py-6 h-full overflow-hidden">
      <div className="w-full flex justify-between items-center px-4">
        <div className="flex items-center gap-4">
           <button onClick={onClose} className="text-gray-500 hover:text-white transition">
             <i className="fas fa-chevron-left mr-2"></i>返回
           </button>
           <span className="px-3 py-1 bg-gray-800 rounded-full text-xs text-gray-400 font-mono">
             {currentIndex + 1} / {cards.length}
           </span>
        </div>
        <div className="flex gap-4">
          <button onClick={handleExportImage} className="text-xs text-pink-400 hover:text-pink-300 transition flex items-center gap-1">
            <i className="fas fa-download"></i> 导出精美图片
          </button>
          <button onClick={() => onNavigateToSource(card.sourceNoteId)} className="text-xs text-blue-400 hover:text-blue-300 transition flex items-center gap-1">
            <i className="fas fa-location-arrow"></i> 定位原文
          </button>
        </div>
      </div>

      <div ref={cardRef} className="w-full flex-1 flex flex-col bg-gray-900 border border-gray-800 rounded-[32px] overflow-hidden shadow-2xl">
        <div className="flex-[4] flex flex-col items-center justify-center p-8 text-center bg-gray-900/50">
           <span className="text-[10px] uppercase tracking-[0.2em] text-gray-600 mb-6 font-bold">知识提问 (Question)</span>
           <h2 className="text-2xl md:text-3xl font-semibold text-gray-100 max-w-lg">{card.front}</h2>
           <div className="mt-6 flex flex-wrap justify-center gap-2">
             {card.tags.map(t => <span key={t} className="px-3 py-1 bg-gray-800/50 rounded-lg text-[10px] text-gray-500">#{t}</span>)}
           </div>
        </div>

        <div className="h-px w-full bg-gradient-to-r from-transparent via-gray-800 to-transparent relative">
           {!isFlipped && (
              <div className="absolute inset-0 flex items-center justify-center -translate-y-1/2">
                <button onClick={() => setIsFlipped(true)} className="px-6 py-2 bg-blue-600 rounded-full text-sm font-bold shadow-xl">揭晓答案</button>
              </div>
           )}
        </div>

        <div className={`flex-[6] flex flex-col p-8 transition-all duration-700 ${!isFlipped ? 'blur-md grayscale opacity-20' : 'blur-0'}`}>
           <div className="flex justify-between items-start mb-4">
              <span className="text-[10px] uppercase tracking-[0.2em] text-blue-500 font-bold">深度解析 (Answer)</span>
              {isFlipped && (
                <button onClick={() => onSpeak(card.back)} className="w-8 h-8 rounded-full bg-blue-600/10 text-blue-400 flex items-center justify-center">
                  <i className="fas fa-volume-up text-xs"></i>
                </button>
              )}
           </div>
           <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
              <p className="text-lg md:text-xl text-gray-300 leading-relaxed whitespace-pre-wrap">
                {isFlipped ? card.back : "••••••••••••••••"}
              </p>
           </div>
        </div>
      </div>

      <div className="w-full flex gap-4 min-h-[64px]">
        {isFlipped ? (
          <>
            <button onClick={() => handleNext(false)} className="flex-1 bg-red-900/20 border border-red-500/30 text-red-400 rounded-2xl font-bold transition">没记住</button>
            <button onClick={() => handleNext(true)} className="flex-1 bg-green-900/20 border border-green-500/30 text-green-400 rounded-2xl font-bold transition">已掌握</button>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-gray-600 text-sm italic">思考并点击揭晓</div>
        )}
      </div>
    </div>
  );
};

