import React, { useState, useEffect } from 'react';
import { AppView, Note, Flashcard, UserStats, QuizQuestion, DemoStep, LearningPlan, PlanTask } from './types';
import { Editor } from './components/Editor';
import { FlashcardView } from './components/FlashcardView';
import { KnowledgeGraph } from './components/KnowledgeGraph';
import { DynamicDemoView } from './components/DynamicDemoView';
import { QuizView } from './components/QuizView';
import { RewardView } from './components/RewardView';
import { KnowledgeLibrary } from './components/KnowledgeLibrary';
import { LearningPlanView } from './components/LearningPlanView';
import { 
  generateFlashcardsFromNote, 
  generateQuiz, 
  speakSweetly, 
  generateDynamicDemo,
  generateLearningPlan,
  analyzePdf 
} from './geminiService';

const INITIAL_NOTE: Note = {
  id: '1',
  title: '欢迎来到 SILI 智能学习',
  content: '# 开始你的进化\n\n- 在 **知识库** 管理你的 PDF 和笔记。\n- 使用 **智能规划** 对话定制宏观与微观目标。\n- 导出 **精美卡片图** 分享学习成果。',
  updatedAt: Date.now()
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('sili_notes_v4');
    return saved ? JSON.parse(saved) : [INITIAL_NOTE];
  });
  const [cards, setCards] = useState<Flashcard[]>(() => {
    const saved = localStorage.getItem('sili_cards_v4');
    return saved ? JSON.parse(saved) : [];
  });
  const [plans, setPlans] = useState<LearningPlan[]>(() => {
    const saved = localStorage.getItem('sili_plans_v4');
    return saved ? JSON.parse(saved) : [];
  });
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('sili_stats_v4');
    return saved ? JSON.parse(saved) : { xp: 0, level: 1, streak: 1, completedCards: 0, lastActive: new Date().toISOString() };
  });

  const [activeNoteId, setActiveNoteId] = useState<string>(notes[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingText, setLoadingText] = useState("正在为您构建智能连接...");
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [demoSteps, setDemoSteps] = useState<DemoStep[]>([]);
  const [userPlanReq, setUserPlanReq] = useState("");

  useEffect(() => {
    localStorage.setItem('sili_notes_v4', JSON.stringify(notes));
    localStorage.setItem('sili_cards_v4', JSON.stringify(cards));
    localStorage.setItem('sili_plans_v4', JSON.stringify(plans));
    localStorage.setItem('sili_stats_v4', JSON.stringify(stats));
  }, [notes, cards, plans, stats]);

  const activeNote = notes.find(n => n.id === activeNoteId) || notes[0];

  const handleCreatePlan = async () => {
    if (!userPlanReq) {
      alert("请输入您的具体学习目标，以便 SILI 为您量身定制。");
      return;
    }
    setLoadingText("正在为您推演宏观与微观进化路径...");
    setIsGenerating(true);
    try {
      const plan = await generateLearningPlan(activeNote.content.substring(0, 2000), userPlanReq);
      setPlans([plan, ...plans]);
      speakSweetly("已经为你量身定制好了双重规划，每一步我都陪着你哦！", "encourage");
    } finally {
      setIsGenerating(false);
      setUserPlanReq("");
    }
  };

  const toggleTask = (planId: string, taskId: string) => {
    setPlans(prev => prev.map(p => {
      if (p.id === planId) {
        return {
          ...p,
          daily: p.daily.map(t => t.id === taskId ? { ...t, done: !t.done } : t)
        };
      }
      return p;
    }));
  };

  const handleImport = async (title: string, data: string, isPdf: boolean) => {
    if (isPdf) {
      setLoadingText("正在深度解析 PDF ...");
      setIsGenerating(true);
      try {
        const text = await analyzePdf(data);
        const n = { id: Date.now().toString(), title, content: text, updatedAt: Date.now(), type: 'pdf' as const };
        setNotes(prev => [n, ...prev]);
        setActiveNoteId(n.id);
      } finally { setIsGenerating(false); }
    } else {
      const n = { id: Date.now().toString(), title, content: data, updatedAt: Date.now(), type: 'note' as const };
      setNotes(prev => [n, ...prev]);
      setActiveNoteId(n.id);
    }
  };

  return (
    <div className="flex h-screen bg-gray-950 text-gray-100 overflow-hidden font-sans">
      <nav className="w-16 md:w-64 flex flex-col bg-gray-900 border-r border-gray-800 z-30">
        <div className="p-6 mb-8 flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-pink-500 to-purple-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg">S</div>
          <span className="hidden md:block font-bold text-lg">SILI System</span>
        </div>
        <div className="flex-1 px-3 space-y-2">
          {[
            { id: AppView.DASHBOARD, icon: 'fa-home', label: '控制台' },
            { id: AppView.LIBRARY, icon: 'fa-database', label: '知识库库' },
            { id: AppView.EDITOR, icon: 'fa-pen-nib', label: '知识编织' },
            { id: AppView.REVIEW, icon: 'fa-layer-group', label: '记忆强化' },
            { id: AppView.GRAPH, icon: 'fa-project-diagram', label: '脑图谱' },
          ].map(item => (
            <button key={item.id} onClick={() => setView(item.id as AppView)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition ${view === item.id ? 'bg-pink-600/10 text-pink-400 font-semibold' : 'text-gray-500 hover:bg-gray-800'}`}>
              <i className={`fas ${item.icon} w-5`}></i>
              <span className="hidden md:block text-sm">{item.label}</span>
            </button>
          ))}
        </div>
      </nav>

      <main className="flex-1 overflow-hidden flex flex-col">
        <header className="h-16 flex items-center justify-between px-8 border-b border-gray-800 bg-gray-950/50 backdrop-blur-md">
          <h2 className="text-sm font-medium text-gray-400">
            {view === AppView.DASHBOARD && '欢迎回来，开始进化'}
            {view === AppView.LIBRARY && '知识库管理中心'}
            {view === AppView.EDITOR && `正在编辑：${activeNote.title}`}
          </h2>
          <div className="text-orange-400 font-bold text-xs uppercase"><i className="fas fa-fire"></i> {stats.streak} DAYS</div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 scroll-smooth">
          {view === AppView.DASHBOARD && (
            <div className="max-w-7xl mx-auto space-y-10">
              <section className="bg-gradient-to-r from-pink-900/40 to-indigo-900/40 border border-pink-500/20 p-8 rounded-[32px] shadow-2xl">
                <h1 className="text-3xl font-bold mb-4">定制你的进化之路</h1>
                <div className="flex gap-4">
                  <input 
                    value={userPlanReq}
                    onChange={(e) => setUserPlanReq(e.target.value)}
                    placeholder="输入目标，如：零实习冲击春招大厂，2-6月计划..."
                    className="flex-1 bg-gray-950/50 border border-pink-500/20 rounded-2xl px-6 focus:outline-none focus:border-pink-500 transition"
                  />
                  <button onClick={handleCreatePlan} className="px-8 py-4 bg-pink-600 hover:bg-pink-500 rounded-2xl font-bold transition flex items-center gap-2">
                    智能排班 <i className="fas fa-magic"></i>
                  </button>
                </div>
              </section>

              {plans.length > 0 && (
                <LearningPlanView 
                  plan={plans[0]} 
                  onToggleTask={(tid) => toggleTask(plans[0].id, tid)} 
                />
              )}
            </div>
          )}

          {view === AppView.LIBRARY && (
            <KnowledgeLibrary 
              notes={notes} 
              cards={cards} 
              onDeleteNote={(id) => setNotes(prev => prev.filter(n => n.id !== id))}
              onDeleteCard={(id) => setCards(prev => prev.filter(c => c.id !== id))}
              onSelectNote={(id) => { setActiveNoteId(id); setView(AppView.EDITOR); }}
            />
          )}

          {view === AppView.EDITOR && (
            <div className="h-full flex gap-6">
              <div className="flex-1">
                <Editor note={activeNote} isGenerating={isGenerating} onSave={(n) => setNotes(prev => prev.map(p => p.id === n.id ? n : p))} 
                  onImport={handleImport} onGenerateCards={async (c) => {
                    setLoadingText("提取卡片中..."); setIsGenerating(true);
                    try {
                      const newCards = await generateFlashcardsFromNote(c, activeNoteId);
                      setCards(prev => [...prev, ...newCards]);
                    } finally { setIsGenerating(false); }
                  }}
                  onGenerateQuiz={async (c) => {
                    setLoadingText("准备题目中..."); setIsGenerating(true);
                    try {
                      const qs = await generateQuiz(c); setQuizQuestions(qs); setView(AppView.QUIZ);
                    } finally { setIsGenerating(false); }
                  }}
                  onStartDemo={async (c) => {
                    setLoadingText("逻辑推演中..."); setIsGenerating(true);
                    try {
                      const steps = await generateDynamicDemo(c); setDemoSteps(steps); setView(AppView.DEMO);
                    } finally { setIsGenerating(false); }
                  }}
                />
              </div>
            </div>
          )}

          {view === AppView.REVIEW && (
            <FlashcardView 
              cards={cards.filter(c => c.nextReview <= Date.now())}
              onReview={(id, ok) => {
                setCards(prev => prev.map(c => {
                  if (c.id === id) {
                    const nl = ok ? Math.min(5, c.level + 1) : 0;
                    return { ...c, level: nl, nextReview: Date.now() + (nl || 1) * 86400000 };
                  }
                  return c;
                }));
                if (ok) setStats(s => ({ ...s, xp: s.xp + 10 }));
              }}
              onSpeak={speakSweetly}
              onNavigateToSource={(id) => { setActiveNoteId(id); setView(AppView.EDITOR); }}
              onClose={() => setView(AppView.DASHBOARD)}
            />
          )}

          {view === AppView.DEMO && <DynamicDemoView steps={demoSteps} onSpeak={speakSweetly} onClose={() => setView(AppView.EDITOR)} />}
          {view === AppView.QUIZ && <QuizView questions={quizQuestions} onClose={() => setView(AppView.EDITOR)} onComplete={() => setView(AppView.REWARD)} />}
          {view === AppView.REWARD && <RewardView stats={stats} onBack={() => setView(AppView.DASHBOARD)} onSpeak={speakSweetly} />}
          {view === AppView.GRAPH && <KnowledgeGraph notes={notes} cards={cards} />}
        </div>
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex flex-col items-center justify-center">
          <div className="w-24 h-24 mb-12 relative animate-spin">
             <div className="absolute inset-0 border-4 border-t-pink-500 rounded-full"></div>
          </div>
          <p className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">{loadingText}</p>
        </div>
      )}
    </div>
  );
};

