import React, { useState, useEffect, useRef } from 'react';
import { LearningPlan, PlanTask } from '../types';

interface LearningPlanViewProps {
  plan: LearningPlan;
  onToggleTask: (taskId: string) => void;
  onUpdateTask: (taskId: string, updates: Partial<PlanTask>) => void;
}

export const LearningPlanView: React.FC<LearningPlanViewProps> = ({ plan, onToggleTask, onUpdateTask }) => {
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);
  const timerRef = useRef<number | null>(null);

  // Statistics calculation
  const totalUnits = plan.daily.reduce((acc, curr) => acc + (curr.units || 0), 0);
  const completedUnits = plan.daily.filter(t => t.done).reduce((acc, curr) => acc + (curr.units || 0), 0);
  const remainingUnits = totalUnits - completedUnits;
  const totalTimeSpentMinutes = completedUnits * 30; // Assuming 1 unit = 30 mins

  useEffect(() => {
    if (activeTaskId) {
      timerRef.current = window.setInterval(() => {
        const task = plan.daily.find(t => t.id === activeTaskId);
        if (task && task.remainingSeconds && task.remainingSeconds > 0) {
          onUpdateTask(activeTaskId, { remainingSeconds: task.remainingSeconds - 1 });
        } else if (task && task.remainingSeconds === 0) {
          // Timer finished
          handleStopTimer(activeTaskId);
          onToggleTask(activeTaskId);
        }
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeTaskId, plan.daily]);

  const handleStartTimer = (task: PlanTask) => {
    if (activeTaskId === task.id) {
      handleStopTimer(task.id);
      return;
    }

    // Default 30 minutes if not set
    const seconds = task.remainingSeconds ?? (task.units ? task.units * 30 * 60 : 30 * 60);
    onUpdateTask(task.id, { remainingSeconds: seconds, isActive: true });
    setActiveTaskId(task.id);
  };

  const handleStopTimer = (taskId: string) => {
    onUpdateTask(taskId, { isActive: false });
    setActiveTaskId(null);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full overflow-hidden">
      {/* Macro Planning Column */}
      <div className="space-y-6 overflow-y-auto pr-4 custom-scrollbar">
        <h3 className="text-xl font-bold flex items-center gap-2 sticky top-0 bg-gray-950 py-2 z-10">
          <i className="fas fa-map-marked-alt text-pink-400"></i>
          宏观路线：{plan.goal}
        </h3>

        {/* Units Analytics Dashboard */}
        <div className="grid grid-cols-3 gap-3 mb-6">
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold">总分配单位</div>
            <div className="text-xl font-black text-blue-400">{totalUnits}</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold">已完成单位</div>
            <div className="text-xl font-black text-green-400">{completedUnits}</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold">总学习时长</div>
            <div className="text-xl font-black text-pink-400">{Math.floor(totalTimeSpentMinutes / 60)}h {totalTimeSpentMinutes % 60}m</div>
          </div>
        </div>

        <div className="relative border-l-2 border-gray-800 ml-4 pl-8 space-y-10">
          {plan.macro.map((m, idx) => (
            <div key={idx} className="relative">
              <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-pink-500 shadow-[0_0_10px_rgba(236,72,153,0.5)] border-4 border-gray-950"></div>
              <h4 className="text-lg font-bold text-pink-400 mb-4">{m.month}</h4>
              <ul className="space-y-3">
                {m.milestones.map((ms, j) => (
                  <li key={j} className="flex items-start gap-3 text-sm text-gray-300">
                    <i className="fas fa-check-circle text-gray-700 mt-1"></i>
                    {ms}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      {/* Daily Micro Planning Column */}
      <div className="bg-gray-900/50 border border-gray-800 rounded-[32px] p-8 flex flex-col overflow-hidden shadow-2xl">
        <div className="mb-6">
          <h3 className="text-xl font-bold flex items-center justify-between mb-2">
            <span className="flex items-center gap-2">
              <i className="fas fa-clock text-blue-400"></i>
              今日深度排班
            </span>
            <span className="text-[10px] bg-blue-500/10 text-blue-400 px-3 py-1 rounded-full font-bold uppercase tracking-widest">
              剩余 {remainingUnits} 单位
            </span>
          </h3>
          <p className="text-xs text-gray-500">点击任务卡片右侧的 <i className="fas fa-play text-[8px]"></i> 开启计时器，每单位默认为 30 分钟深度专注。</p>
        </div>

        <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {plan.daily.map(task => (
            <div 
              key={task.id} 
              className={`flex items-center gap-4 p-4 rounded-2xl border transition-all ${
                task.done ? 'bg-green-500/10 border-green-500/30 opacity-70' : 
                task.isActive ? 'bg-pink-500/5 border-pink-500/40 shadow-lg shadow-pink-500/10' : 
                'bg-gray-800/30 border-gray-700 hover:border-blue-500/50'
              }`}
            >
              {/* Checkbox */}
              <div 
                onClick={() => onToggleTask(task.id)}
                className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition cursor-pointer shrink-0 ${
                  task.done ? 'bg-green-500 border-green-500 text-white' : 'border-gray-600'
                }`}
              >
                {task.done && <i className="fas fa-check text-[10px]"></i>}
              </div>

              {/* Task Content */}
              <div className="flex-1 min-w-0" onClick={() => onToggleTask(task.id)}>
                <div className="flex justify-between items-start">
                  <span className={`text-sm font-bold truncate block ${task.done ? 'text-gray-500 line-through' : 'text-gray-200'}`}>
                    {task.time && <span className="text-blue-400 mr-2">[{task.time}]</span>}
                    {task.task}
                  </span>
                </div>
                {task.units && (
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-[9px] text-gray-500 uppercase tracking-widest font-bold">
                      {task.units} 学习单位
                    </span>
                    {task.done && <span className="text-[9px] text-green-500 font-bold uppercase tracking-widest">已达成</span>}
                  </div>
                )}
              </div>

              {/* Timer Button */}
              {!task.done && (
                <div className="flex items-center gap-3 pl-2 border-l border-gray-800">
                  {task.remainingSeconds !== undefined && (
                    <span className={`font-mono text-sm font-bold ${task.isActive ? 'text-pink-500' : 'text-gray-500'}`}>
                      {formatTime(task.remainingSeconds)}
                    </span>
                  )}
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleStartTimer(task); }}
                    className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
                      task.isActive 
                        ? 'bg-pink-600 text-white shadow-lg shadow-pink-600/30 animate-pulse' 
                        : 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white'
                    }`}
                  >
                    <i className={`fas ${task.isActive ? 'fa-pause' : 'fa-play'} text-xs`}></i>
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>

        <div className="mt-6 pt-6 border-t border-gray-800">
          <div className="flex justify-between text-[10px] font-bold text-gray-500 mb-2 uppercase tracking-widest">
            <span>今日进化进度</span>
            <span className="text-pink-400">{Math.round((completedUnits / (totalUnits || 1)) * 100)}%</span>
          </div>
          <div className="h-1.5 w-full bg-gray-800 rounded-full overflow-hidden">
            <div 
              className="h-full bg-gradient-to-r from-blue-600 via-pink-500 to-green-500 transition-all duration-1000" 
              style={{ width: `${(completedUnits / (totalUnits || 1)) * 100}%` }}
            ></div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, Note, Flashcard, UserStats, QuizQuestion, DemoStep, LearningPlan, PlanTask } from './types';
import { Editor } from './components/Editor';
import { FlashcardView } from './components/FlashcardView';
import { KnowledgeGraph } from './components/KnowledgeGraph';
import { DynamicDemoView } from './components/DynamicDemoView';
import { QuizView } from './components/QuizView';
import { RewardView } from './components/RewardView';
import { KnowledgeLibrary } from './components/KnowledgeLibrary';
import { LearningPlanView } from './components/LearningPlanView';
import { 
  generateFlashcardsFromNote, 
  generateQuiz, 
  speakSweetly, 
  generateDynamicDemo,
  generateLearningPlan,
  analyzePdf 
} from './geminiService';

const INITIAL_NOTE: Note = {
  id: '1',
  title: '欢迎来到 SILI 智能学习',
  content: '# 开始你的进化\n\n- 在 **知识库** 管理你的 PDF 和笔记。\n- 使用 **智能规划** 对话定制宏观与微观目标。\n- 导出 **精美卡片图** 分享学习成果。',
  updatedAt: Date.now()
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('sili_notes_v5');
    return saved ? JSON.parse(saved) : [INITIAL_NOTE];
  });
  const [cards, setCards] = useState<Flashcard[]>(() => {
    const saved = localStorage.getItem('sili_cards_v5');
    return saved ? JSON.parse(saved) : [];
  });
  const [plans, setPlans] = useState<LearningPlan[]>(() => {
    const saved = localStorage.getItem('sili_plans_v5');
    return saved ? JSON.parse(saved) : [];
  });
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('sili_stats_v5');
    return saved ? JSON.parse(saved) : { xp: 0, level: 1, streak: 1, completedCards: 0, lastActive: new Date().toISOString() };
  });

  const [activeNoteId, setActiveNoteId] = useState<string>(notes[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingText, setLoadingText] = useState("正在为您构建智能连接...");
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [demoSteps, setDemoSteps] = useState<DemoStep[]>([]);
  const [userPlanReq, setUserPlanReq] = useState("");

  useEffect(() => {
    localStorage.setItem('sili_notes_v5', JSON.stringify(notes));
    localStorage.setItem('sili_cards_v5', JSON.stringify(cards));
    localStorage.setItem('sili_plans_v5', JSON.stringify(plans));
    localStorage.setItem('sili_stats_v5', JSON.stringify(stats));
  }, [notes, cards, plans, stats]);

  const activeNote = notes.find(n => n.id === activeNoteId) || notes[0];

  const handleCreatePlan = async () => {
    if (!userPlanReq) {
      alert("请输入您的具体学习目标，以便 SILI 为您量身定制。");
      return;
    }
    setLoadingText("正在为您推演宏观与微观进化路径...");
    setIsGenerating(true);
    try {
      const plan = await generateLearningPlan(activeNote.content.substring(0, 2000), userPlanReq);
      setPlans([plan, ...plans]);
      speakSweetly("已经为你量身定制好了双重规划，每一步我都陪着你哦！", "encourage");
    } finally {
      setIsGenerating(false);
      setUserPlanReq("");
    }
  };

  const toggleTask = (planId: string, taskId: string) => {
    setPlans(prev => prev.map(p => {
      if (p.id === planId) {
        return {
          ...p,
          daily: p.daily.map(t => t.id === taskId ? { ...t, done: !t.done, isActive: false } : t)
        };
      }
      return p;
    }));
    // Gain XP for completing tasks
    setStats(s => ({ ...s, xp: s.xp + 20 }));
  };

  const updateTask = (planId: string, taskId: string, updates: Partial<PlanTask>) => {
    setPlans(prev => prev.map(p => {
      if (p.id === planId) {
        return {
          ...p,
          daily: p.daily.map(t => t.id === taskId ? { ...t, ...updates } : t)
        };
      }
      return p;
    }));
  };

  const handleImport = async (title: string, data: string, isPdf: boolean) => {
    if (isPdf) {
      setLoadingText("正在深度解析 PDF ...");
      setIsGenerating(true);
      try {
        const text = await analyzePdf(data);
        const n = { id: Date.now().toString(), title, content: text, updatedAt: Date.now(), type: 'pdf' as const };
        setNotes(prev => [n, ...prev]);
        setActiveNoteId(n.id);
      } finally { setIsGenerating(false); }
    } else {
      const n = { id: Date.now().toString(), title, content: data, updatedAt: Date.now(), type: 'note' as const };
      setNotes(prev => [n, ...prev]);
      setActiveNoteId(n.id);
    }
  };

  return (
    <div className="flex h-screen bg-gray-950 text-gray-100 overflow-hidden font-sans">
      <nav className="w-16 md:w-64 flex flex-col bg-gray-900 border-r border-gray-800 z-30">
        <div className="p-6 mb-8 flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-pink-500 to-purple-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg">S</div>
          <span className="hidden md:block font-bold text-lg">SILI System</span>
        </div>
        <div className="flex-1 px-3 space-y-2">
          {[
            { id: AppView.DASHBOARD, icon: 'fa-home', label: '控制台' },
            { id: AppView.LIBRARY, icon: 'fa-database', label: '知识库库' },
            { id: AppView.EDITOR, icon: 'fa-pen-nib', label: '知识编织' },
            { id: AppView.REVIEW, icon: 'fa-layer-group', label: '记忆强化' },
            { id: AppView.GRAPH, icon: 'fa-project-diagram', label: '脑图谱' },
          ].map(item => (
            <button key={item.id} onClick={() => setView(item.id as AppView)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition ${view === item.id ? 'bg-pink-600/10 text-pink-400 font-semibold' : 'text-gray-500 hover:bg-gray-800'}`}>
              <i className={`fas ${item.icon} w-5`}></i>
              <span className="hidden md:block text-sm">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="p-4 mt-auto">
          <div className="hidden md:block bg-gray-800/50 rounded-2xl p-4 border border-gray-700/50">
             <div className="flex justify-between text-[10px] mb-2 font-bold text-gray-500 uppercase tracking-widest">
               <span>LV.{stats.level}</span>
               <span className="text-pink-400">{stats.xp % 500} / 500 XP</span>
             </div>
             <div className="h-1 w-full bg-gray-800 rounded-full overflow-hidden">
               <div className="h-full bg-pink-500 shadow-[0_0_8px_rgba(236,72,153,0.5)] transition-all duration-500" style={{ width: `${(stats.xp % 500) / 5.0}%` }}></div>
             </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 overflow-hidden flex flex-col">
        <header className="h-16 flex items-center justify-between px-8 border-b border-gray-800 bg-gray-950/50 backdrop-blur-md">
          <h2 className="text-sm font-medium text-gray-400">
            {view === AppView.DASHBOARD && '欢迎回来，开始进化'}
            {view === AppView.LIBRARY && '知识库管理中心'}
            {view === AppView.EDITOR && `正在编辑：${activeNote.title}`}
          </h2>
          <div className="text-orange-400 font-bold text-xs uppercase tracking-tighter flex items-center gap-2">
            <i className="fas fa-fire"></i> {stats.streak} DAYS STREAK
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 scroll-smooth">
          {view === AppView.DASHBOARD && (
            <div className="max-w-7xl mx-auto space-y-10">
              <section className="bg-gradient-to-r from-pink-900/40 to-indigo-900/40 border border-pink-500/20 p-10 rounded-[40px] shadow-2xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 group-hover:rotate-0 transition-transform duration-1000">
                  <i className="fas fa-brain text-[120px]"></i>
                </div>
                <div className="relative z-10">
                  <h1 className="text-4xl font-black mb-4 tracking-tight">定制你的进化之路</h1>
                  <p className="text-pink-100/60 max-w-lg mb-8 leading-relaxed">基于你最近的学习内容，我将为你量身定制一个科学的学习周期和重点提示。</p>
                  <div className="flex flex-col md:flex-row gap-4">
                    <input 
                      value={userPlanReq}
                      onChange={(e) => setUserPlanReq(e.target.value)}
                      placeholder="输入目标，如：零实习冲击春招大厂，2-6月计划..."
                      className="flex-1 bg-gray-950/50 border border-pink-500/20 rounded-2xl px-6 py-4 focus:outline-none focus:border-pink-500 transition shadow-inner"
                    />
                    <button onClick={handleCreatePlan} className="px-10 py-4 bg-pink-600 hover:bg-pink-500 rounded-2xl font-black text-sm uppercase tracking-widest transition flex items-center justify-center gap-2 shadow-xl shadow-pink-900/40 active:scale-95">
                      开始智能排班 <i className="fas fa-magic"></i>
                    </button>
                  </div>
                </div>
              </section>

              {plans.length > 0 && (
                <LearningPlanView 
                  plan={plans[0]} 
                  onToggleTask={(tid) => toggleTask(plans[0].id, tid)} 
                  onUpdateTask={(tid, updates) => updateTask(plans[0].id, tid, updates)}
                />
              )}
            </div>
          )}

          {view === AppView.LIBRARY && (
            <KnowledgeLibrary 
              notes={notes} 
              cards={cards} 
              onDeleteNote={(id) => setNotes(prev => prev.filter(n => n.id !== id))}
              onDeleteCard={(id) => setCards(prev => prev.filter(c => c.id !== id))}
              onSelectNote={(id) => { setActiveNoteId(id); setView(AppView.EDITOR); }}
            />
          )}

          {view === AppView.EDITOR && (
            <div className="h-full flex gap-6">
              <div className="flex-1">
                <Editor note={activeNote} isGenerating={isGenerating} onSave={(n) => setNotes(prev => prev.map(p => p.id === n.id ? n : p))} 
                  onImport={handleImport} onGenerateCards={async (c) => {
                    setLoadingText("提取卡片中..."); setIsGenerating(true);
                    try {
                      const newCards = await generateFlashcardsFromNote(c, activeNoteId);
                      setCards(prev => [...prev, ...newCards]);
                    } finally { setIsGenerating(false); }
                  }}
                  onGenerateQuiz={async (c) => {
                    setLoadingText("准备题目中..."); setIsGenerating(true);
                    try {
                      const qs = await generateQuiz(c); setQuizQuestions(qs); setView(AppView.QUIZ);
                    } finally { setIsGenerating(false); }
                  }}
                  onStartDemo={async (c) => {
                    setLoadingText("逻辑推演中..."); setIsGenerating(true);
                    try {
                      const steps = await generateDynamicDemo(c); setDemoSteps(steps); setView(AppView.DEMO);
                    } finally { setIsGenerating(false); }
                  }}
                />
              </div>
            </div>
          )}

          {view === AppView.REVIEW && (
            <FlashcardView 
              cards={cards.filter(c => c.nextReview <= Date.now())}
              onReview={(id, ok) => {
                setCards(prev => prev.map(c => {
                  if (c.id === id) {
                    const nl = ok ? Math.min(5, c.level + 1) : 0;
                    return { ...c, level: nl, nextReview: Date.now() + (nl || 1) * 86400000 };
                  }
                  return c;
                }));
                if (ok) setStats(s => ({ ...s, xp: s.xp + 10 }));
              }}
              onSpeak={speakSweetly}
              onNavigateToSource={(id) => { setActiveNoteId(id); setView(AppView.EDITOR); }}
              onClose={() => setView(AppView.DASHBOARD)}
            />
          )}

          {view === AppView.DEMO && <DynamicDemoView steps={demoSteps} onSpeak={speakSweetly} onClose={() => setView(AppView.EDITOR)} />}
          {view === AppView.QUIZ && <QuizView questions={quizQuestions} onClose={() => setView(AppView.EDITOR)} onComplete={() => setView(AppView.REWARD)} />}
          {view === AppView.REWARD && <RewardView stats={stats} onBack={() => setView(AppView.DASHBOARD)} onSpeak={speakSweetly} />}
          {view === AppView.GRAPH && <KnowledgeGraph notes={notes} cards={cards} />}
        </div>
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-300">
          <div className="w-24 h-24 mb-12 relative">
             <div className="absolute inset-0 border-4 border-pink-500/20 rounded-full"></div>
             <div className="absolute inset-0 border-4 border-t-pink-500 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
               <i className="fas fa-brain text-2xl text-pink-500 animate-pulse"></i>
             </div>
          </div>
          <p className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">{loadingText}</p>
        </div>
      )}
    </div>
  );
};

