import React, { useState, useEffect, useRef, useMemo } from 'react';
import { LearningPlan, PlanTask } from '../types';

interface LearningPlanViewProps {
  plan: LearningPlan;
  onToggleTask: (taskId: string) => void;
  onUpdateTask: (taskId: string, updates: Partial<PlanTask>) => void;
}

// Memoized individual task item for faster response
const TaskItem = React.memo(({ 
  task, 
  onToggle, 
  onStartTimer, 
  formatTime 
}: { 
  task: PlanTask, 
  onToggle: (id: string) => void, 
  onStartTimer: (t: PlanTask) => void,
  formatTime: (s: number) => string
}) => {
  return (
    <div 
      className={`flex items-center gap-4 p-4 rounded-2xl border transition-all duration-200 ${
        task.done ? 'bg-green-500/10 border-green-500/30 opacity-70' : 
        task.isActive ? 'bg-pink-500/5 border-pink-500/40 shadow-lg shadow-pink-500/10' : 
        'bg-gray-800/30 border-gray-700 hover:border-blue-500/50'
      }`}
    >
      <div 
        onClick={() => onToggle(task.id)}
        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition cursor-pointer shrink-0 ${
          task.done ? 'bg-green-500 border-green-500 text-white' : 'border-gray-600 hover:border-pink-400'
        }`}
      >
        {task.done && <i className="fas fa-check text-[10px]"></i>}
      </div>

      <div className="flex-1 min-w-0" onClick={() => onToggle(task.id)}>
        <div className="flex justify-between items-start">
          <span className={`text-sm font-bold truncate block ${task.done ? 'text-gray-500 line-through' : 'text-gray-200'}`}>
            {task.time && <span className="text-blue-400 mr-2 font-mono">[{task.time}]</span>}
            {task.task}
          </span>
        </div>
        {task.units && (
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[9px] text-gray-500 uppercase tracking-widest font-bold">
              {task.units} 学习单位
            </span>
            {task.done && <span className="text-[9px] text-green-500 font-bold uppercase tracking-widest animate-pulse">DONE</span>}
          </div>
        )}
      </div>

      {!task.done && (
        <div className="flex items-center gap-3 pl-3 border-l border-gray-800">
          {task.remainingSeconds !== undefined && (
            <span className={`font-mono text-sm font-bold w-12 text-center ${task.isActive ? 'text-pink-500' : 'text-gray-500'}`}>
              {formatTime(task.remainingSeconds)}
            </span>
          )}
          <button 
            onClick={(e) => { e.stopPropagation(); onStartTimer(task); }}
            className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
              task.isActive 
                ? 'bg-pink-600 text-white shadow-lg shadow-pink-600/30' 
                : 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white'
            }`}
          >
            <i className={`fas ${task.isActive ? 'fa-pause' : 'fa-play'} text-xs`}></i>
          </button>
        </div>
      )}
    </div>
  );
});

export const LearningPlanView: React.FC<LearningPlanViewProps> = ({ plan, onToggleTask, onUpdateTask }) => {
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);
  const timerRef = useRef<number | null>(null);

  // Statistics calculation with useMemo for speed
  const stats = useMemo(() => {
    const totalUnits = plan.daily.reduce((acc, curr) => acc + (curr.units || 0), 0);
    const completedUnits = plan.daily.filter(t => t.done).reduce((acc, curr) => acc + (curr.units || 0), 0);
    const remainingUnits = totalUnits - completedUnits;
    const totalTimeMinutes = completedUnits * 30; // Assuming 1 unit = 30 mins
    return { totalUnits, completedUnits, remainingUnits, totalTimeMinutes };
  }, [plan.daily]);

  useEffect(() => {
    if (activeTaskId) {
      timerRef.current = window.setInterval(() => {
        const task = plan.daily.find(t => t.id === activeTaskId);
        if (task && task.remainingSeconds && task.remainingSeconds > 0) {
          onUpdateTask(activeTaskId, { remainingSeconds: task.remainingSeconds - 1 });
        } else if (task && task.remainingSeconds === 0) {
          handleStopTimer(activeTaskId);
          onToggleTask(activeTaskId);
        }
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeTaskId, plan.daily, onUpdateTask, onToggleTask]);

  const handleStartTimer = (task: PlanTask) => {
    if (activeTaskId === task.id) {
      handleStopTimer(task.id);
      return;
    }

    // Default to task's units * 30 minutes, or 30 minutes if unspecified
    const defaultSeconds = (task.units ? task.units * 30 : 30) * 60;
    const seconds = task.remainingSeconds ?? defaultSeconds;

    onUpdateTask(task.id, { remainingSeconds: seconds, isActive: true });
    setActiveTaskId(task.id);
  };

  const handleStopTimer = (taskId: string) => {
    onUpdateTask(taskId, { isActive: false });
    setActiveTaskId(null);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full overflow-hidden">
      <div className="space-y-6 overflow-y-auto pr-4 custom-scrollbar">
        <h3 className="text-xl font-bold flex items-center gap-2 sticky top-0 bg-gray-950 py-2 z-10">
          <i className="fas fa-map-marked-alt text-pink-400"></i>
          宏观路线：{plan.goal}
        </h3>

        <div className="grid grid-cols-3 gap-3 mb-6">
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center shadow-lg">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold tracking-widest">预测分配</div>
            <div className="text-2xl font-black text-blue-400">{stats.totalUnits}</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center shadow-lg">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold tracking-widest">已达单位</div>
            <div className="text-2xl font-black text-green-400">{stats.completedUnits}</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 p-4 rounded-2xl text-center shadow-lg">
            <div className="text-[10px] text-gray-500 uppercase mb-1 font-bold tracking-widest">学习记录</div>
            <div className="text-xl font-black text-pink-400">{Math.floor(stats.totalTimeMinutes / 60)}h {stats.totalTimeMinutes % 60}m</div>
          </div>
        </div>

        <div className="relative border-l-2 border-gray-800 ml-4 pl-8 space-y-10">
          {plan.macro.map((m, idx) => (
            <div key={idx} className="relative">
              <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-pink-500 shadow-[0_0_10px_rgba(236,72,153,0.5)] border-4 border-gray-950"></div>
              <h4 className="text-lg font-bold text-pink-400 mb-4">{m.month}</h4>
              <ul className="space-y-3">
                {m.milestones.map((ms, j) => (
                  <li key={j} className="flex items-start gap-3 text-sm text-gray-300 group">
                    <i className="fas fa-check-circle text-gray-700 mt-1 group-hover:text-pink-500 transition-colors"></i>
                    {ms}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-gray-900/50 border border-gray-800 rounded-[32px] p-8 flex flex-col overflow-hidden shadow-2xl backdrop-blur-sm">
        <div className="mb-6">
          <h3 className="text-xl font-bold flex items-center justify-between mb-2">
            <span className="flex items-center gap-2">
              <i className="fas fa-bolt text-blue-400"></i>
              微观执行：微秒响应
            </span>
            <span className="text-[10px] bg-blue-500/10 text-blue-400 px-3 py-1 rounded-full font-bold uppercase tracking-widest border border-blue-500/20">
              待完成 {stats.remainingUnits} 单位
            </span>
          </h3>
          <p className="text-xs text-gray-500">点击计时开启深度专注模式。每个单位对应 30 分钟。系统已优化反应速度。</p>
        </div>

        <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {plan.daily.map(task => (
            <TaskItem 
              key={task.id} 
              task={task} 
              onToggle={onToggleTask} 
              onStartTimer={handleStartTimer} 
              formatTime={formatTime} 
            />
          ))}
        </div>

        <div className="mt-6 pt-6 border-t border-gray-800">
          <div className="flex justify-between text-[10px] font-bold text-gray-500 mb-2 uppercase tracking-widest">
            <span>今日进化进度 (Daily Evolution)</span>
            <span className="text-pink-400">{Math.round((stats.completedUnits / (stats.totalUnits || 1)) * 100)}%</span>
          </div>
          <div className="h-2 w-full bg-gray-800 rounded-full overflow-hidden shadow-inner">
            <div 
              className="h-full bg-gradient-to-r from-blue-600 via-pink-500 to-green-500 transition-all duration-1000 ease-out" 
              style={{ width: `${(stats.completedUnits / (stats.totalUnits || 1)) * 100}%` }}
            ></div>
          </div>
        </div>
      </div>
    </div>
  );
};

