             <div className="absolute inset-0 border-[6px] border-t-pink-500 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
               <i className="fas fa-microchip text-4xl text-pink-500 animate-pulse"></i>
             </div>
          </div>
          <p className="text-3xl font-black text-white tracking-[0.2em] uppercase animate-pulse">{loadingText}</p>
          <p className="mt-6 text-gray-500 text-sm font-medium italic">SILI 系统正在优化神经通路，请稍候...</p>
        </div>
      )}
    </div>
  );
};

export default App;
